BEGIN; CREATE TABLE IF NOT EXISTS public.accounting_debt_customer_terms (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), customer_id uuid NOT NULL REFERENCES public.customers(id), default_payment_term_days integer NOT NULL DEFAULT 30 CHECK (default_payment_term_days BETWEEN 0 AND 3650), note text NULL, created_at timestamptz NOT NULL DEFAULT now(), created_by uuid NULL REFERENCES public.profiles(id), updated_at timestamptz NOT NULL DEFAULT now(), updated_by uuid NULL REFERENCES public.profiles(id), deleted_at timestamptz NULL, deleted_by uuid NULL REFERENCES public.profiles(id)); CREATE UNIQUE INDEX IF NOT EXISTS idx_acc_debt_customer_terms_customer_live ON public.accounting_debt_customer_terms(customer_id) WHERE deleted_at IS NULL; DROP TRIGGER IF EXISTS trg_acc_debt_customer_terms_touch ON public.accounting_debt_customer_terms; CREATE TRIGGER trg_acc_debt_customer_terms_touch BEFORE INSERT OR UPDATE ON public.accounting_debt_customer_terms FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_touch_row(); DROP TRIGGER IF EXISTS trg_acc_debt_customer_terms_block_delete ON public.accounting_debt_customer_terms; CREATE TRIGGER trg_acc_debt_customer_terms_block_delete BEFORE DELETE ON public.accounting_debt_customer_terms FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_block_hard_delete(); ALTER TABLE public.accounting_debt_customer_terms ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "acc_debt_customer_terms_select" ON public.accounting_debt_customer_terms; CREATE POLICY "acc_debt_customer_terms_select" ON public.accounting_debt_customer_terms FOR SELECT TO authenticated USING (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_customer_terms_insert" ON public.accounting_debt_customer_terms; CREATE POLICY "acc_debt_customer_terms_insert" ON public.accounting_debt_customer_terms FOR INSERT TO authenticated WITH CHECK (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_customer_terms_update" ON public.accounting_debt_customer_terms; CREATE POLICY "acc_debt_customer_terms_update" ON public.accounting_debt_customer_terms FOR UPDATE TO authenticated USING (public.can_manage_accounting_debt()) WITH CHECK (public.can_manage_accounting_debt()); GRANT SELECT, INSERT, UPDATE ON public.accounting_debt_customer_terms TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
